/* 文件头注释：JSON格式化程序，通过遍历字符串并根据字符类型决定缩进和换行 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    string json;
    getline(cin, json); // 读取输入的JSON字符串

    int indentLevel = 0; // 当前缩进级别
    bool inString = false; // 是否在字符串中
    bool afterComma = false; // 是否在逗号后

    for (size_t i = 0; i < json.size(); ++i) {
        char ch = json[i];

        if (ch == '"' && (i == 0 || json[i-1] != '\\')) {
            inString = !inString; // 切换字符串状态
        }

        if (!inString) {
            if (ch == '{' || ch == '[') {
                cout << ch << '\n';
                indentLevel++;
                cout << string(indentLevel * 4, ' '); // 增加缩进
            } else if (ch == '}' || ch == ']') {
                cout << '\n';
                indentLevel--;
                cout << string(indentLevel * 4, ' '); // 减少缩进
                cout << ch;
            } else if (ch == ',') {
                cout << ch << '\n';
                afterComma = true;
                cout << string(indentLevel * 4, ' '); // 保持缩进
            } else if (ch == ':') {
                cout << " : ";
            } else {
                cout << ch;
            }
        } else {
            cout << ch;
        }
    }

    return 0;
}

