#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;

    // 生成所有可能的排列
    vector<string> allPermutations;
    string digits;
    for (int i = 0; i < n; ++i) {
        digits += ('0' + i);
    }
    do {
        allPermutations.push_back(digits);
    } while (next_permutation(digits.begin(), digits.end()));

    // 读取输入的排列
    set<string> inputPermutations;
    for (int i = 0; i < allPermutations.size() - 1; ++i) {
        string s;
        cin >> s;
        inputPermutations.insert(s);
    }

    // 找出缺失的排列
    for (const string& perm : allPermutations) {
        if (inputPermutations.find(perm) == inputPermutations.end()) {
            cout << perm << endl;
            break;
        }
    }

    return 0;
}

