/* 文件头注释：找出缺失的排列 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;

    // 记录每个数字的出现次数
    vector<int> count(n, 0);
    for (int i = 0; i < n; ++i) {
        count[i] = i;
    }

    // 读取输入的排列，并更新每个数字的出现次数
    for (int i = 0; i < factorial(n) - 1; ++i) {
        string s;
        cin >> s;
        for (char c : s) {
            count[c - '0']--;
        }
    }

    // 构造缺失的排列
    string missingPermutation;
    for (int i = 0; i < n; ++i) {
        missingPermutation += ('0' + count[i]);
    }

    cout << missingPermutation << endl;

    return 0;
}

// 计算阶乘的辅助函数
int factorial(int n) {
    int result = 1;
    for (int i = 2; i <= n; ++i) {
        result *= i;
    }
    return result;
}

