/* 文件头注释：找出缺失的排列，使用全排列生成和集合查找 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;

    // 生成所有可能的排列
    vector<int> digits(n);
    for (int i = 0; i < n; ++i) {
        digits[i] = i;
    }

    set<string> allPermutations;
    do {
        string permutation;
        for (int digit : digits) {
            permutation += to_string(digit);
        }
        allPermutations.insert(permutation);
    } while (next_permutation(digits.begin(), digits.end()));

    // 读取输入的排列
    set<string> inputPermutations;
    for (int i = 0; i < allPermutations.size() - 1; ++i) {
        string perm;
        cin >> perm;
        inputPermutations.insert(perm);
    }

    // 找出缺失的排列
    for (const string& perm : allPermutations) {
        if (inputPermutations.find(perm) == inputPermutations.end()) {
            cout << perm << endl;
            break;
        }
    }

    return 0;
}

